@@ -606,11 +562,11 @@ static int dps310_write_raw(struct iio_dev *iio,
 	case IIO_CHAN_INFO_OVERSAMPLING_RATIO:
 		switch (chan->type) {
 		case IIO_PRESSURE:
-			rc = dps310_set_pres_precision(data, val);
+			rc = dps310_set_precision(data, val, PRESSURE);
 			break;

 		case IIO_TEMP:
