 		iio_push_to_buffers_with_timestamp(indio_dev, data, timestamp);
 	}

-end_session:
-	mutex_unlock(&st->lock);
-	iio_trigger_notify_done(indio_dev->trig);
-
-	return IRQ_HANDLED;

 flush_fifo:
 	/* Flush HW and SW FIFOs. */
